args.sparql:
SELECT ?term ?termLabel (SUM(IF(?gender = wd:Q6581097, 1, 0)) AS ?femaleCount), (COUNT(?member) AS ?totalCount), ((SUM(IF(?gender = wd:Q6581097, 1, 0)) * 100.0 / COUNT(?member)) AS ?percentage)
WHERE {
  ?term wdt:P31 wd:Q3139074;
        wdt:P361 wd:Q403035;
        wdt:P580 ?start.
  ?term rdfs:label ?termLabel.
  ?term p:P172 ?memberStmt.
  ?memberStmt ps:P172 ?member.
  ?member wdt:P21 ?gender.
}
GROUP BY ?term ?termLabel ?start
ORDER BY DESC(?start)
LIMIT 4
